  const customHeader = req.headers['x-custom-header'];
  
  const logMessage = `User Action - Username: ${username} - Action: ${action} - Details: ${details} - IP: ${ip} - Custom Header: ${customHeader} - Time: ${new Date().toISOString()}`;
